var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PLAYER_SPORTS_NPC_BLUE","text":{"KOREA":"좋아! 빼앗았다!","JPN":"よし！　取れた！","ENG":"Yeah, I got it!","TWN":"太好了！拿到了！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"PLAYER_SPORTS_NPC_RED","text":{"KOREA":"아깝다! 손을 조금만 더 뻗으면 됐는데......!","JPN":"惜しい！　もう少し手を伸ばせたら届いたのに……！","ENG":"Bummer! I was so close!","TWN":"真可惜！就差一點兒就拿到了……！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"크윽! 임시 편입생! 경기 내내 노골적으로 나만 노리잖아!","JPN":"くっ！　臨時編入生！　露骨に私ばっか狙ってるじゃない！？","ENG":"Bah! You, temporary transfer student! You're being badly after me throughout the whole game!","TWN":"咳咳！臨時插班生！你怎麼一直盯著我不放！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"경기를 너무 치사하게 하는 거 아냐?!","JPN":"試合なのにずるいわよ！！","ENG":"Why are you being so nasty?","TWN":"你不覺得自己太卑鄙了嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"치사하다고 느꼈다면 계획대로네.","JPN":"ずるいと思ったなら計画どおりよ。","ENG":"If you think I'm being nasty, everything is going as I planned.","TWN":"你覺得我卑鄙？那就對了。"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"원래 적팀의 에이스를 마크하는 게 전략의 기본이니까.","JPN":"敵チームのエースをマークするのが戦略の基本だから。","ENG":"Strategy 101: keep the enemy's ace in check.","TWN":"牽制敵隊的王牌本就是最基本的策略。"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"우리 팀 머저리들은 다 뭘 하고 있는 거야!","JPN":"うちのチームの無能どもは何してるの！？","ENG":"What are the other idiots on our team doing?","TWN":"我們隊的蠢貨都在幹什麼！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이래선 내가 활약할 수가 없잖아!","JPN":"これじゃあ私が活躍できないじゃない！","ENG":"I can't shine in a situation like this!","TWN":"這樣我根本就沒辦法大展身手！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"방금 전까지 혼자서 전부 상대할 것처럼 떵떵거리더니 뭐 하는 거야!","JPN":"さっきまで一人で全員相手にできるって威張ってたのに何してるの！","ENG":"Hey, you were bragging that you could take care of them all by yourself! What are you doing now?","TWN":"剛剛還一副以一擋百的架勢呢，現在怎麼了！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"팀전이니까 한 명만 쫓지 말고 다른 팀원들도 도와 줘야지!","JPN":"チーム戦なんだから一人ばかり追いかけてないで、他のチームメンバーも助けてあげて！","ENG":"This is a team match! Stop following her and help the others!","TWN":"這是團隊戰，不要只追著一個人跑，也要幫幫其他隊員才是！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"칫...... 낙오자 주제에 목소리만 커선......!","JPN":"チッ……落ちこぼれのくせに声だけはデカいじゃない……！","ENG":"Hmpf, don't tell me what to do, loser!","TWN":"切……區區一個失敗者，口氣倒是不小……！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"누가 좋아서 이 녀석만 상대하고 있는 줄 알아?!","JPN":"私だって好きでこいつだけを相手してるわけじゃないわよ！？","ENG":"Do you think I'm only dealing with her because I want to?","TWN":"你以為我願意這樣？！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"그러는 넌 네 꼬리는 어디다 두고 다니는 건데!","JPN":"そういうあんたのしっぽはどこなの！","ENG":"Where did you leave your tail, anyway?","TWN":"還有，你的尾巴丟哪兒去了！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응? 내 꼬리?","JPN":"ん？　私のしっぽ？","ENG":"Huh? My tail?","TWN":"嗯？我的尾巴？"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어, 어라? 이게 언제 사라졌지?!","JPN":"あ、あれ？　いつの間に消えたの！？","ENG":"Err, when did I lose it?","TWN":"哎，哎呀？尾巴什麼時候不見的？！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"첫번째 경기 종료!","JPN":"第1試合、終了！","ENG":"The first game is over!","TWN":"第一場比賽結束！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"청팀이 꼬리 다섯 개를 더 모으며 승리를 가져갑니다!","JPN":"青組がしっぽを5つ集めて勝利を手にしました！","ENG":"The Blue Team has won by five tails!","TWN":"藍隊多拿到了五條尾巴，藍隊獲勝！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"강력한 우승 후보였던 나이엘 선수는 꼬리를 하나도 모으지 못했네요.","JPN":"強力な優勝候補だったナイエル選手はしっぽを1つも獲得できていませんね。","ENG":"Naielle, who was considered a front runner, failed to collect even a single tail.","TWN":"強而有力的冠軍種子選手奈爾一條尾巴都沒拿到。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"그리고 첫 경기부터 나이엘 선수를 아무것도 못하게 압박한 서윤 선수!","JPN":"そして初戦からナイエル選手をしっかり追い込んだアオイ選手！","ENG":"And that's because of Seo Yoon, who kept her in check throughout the game!","TWN":"從第一場比賽就完全壓制奈爾選手的徐芸選手！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"임시 편입생인데도 대단한 실력이네요!","JPN":"臨時編入生なのに、すごい実力ですね！","ENG":"This temporary transfer student is a force to be reckoned with!","TWN":"雖然是臨時插班生，但卻實力了得啊！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이 패배자들 같으니! 하나같이 도움이 안 되잖아!","JPN":"もう、使えないわ！　あんたたち全然役に立たないじゃない！","ENG":"You losers! None of you helped at all!","TWN":"你們這些失敗者！真是一點兒忙都幫不上！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"어째서 이 내가 너희들 때문에 패배자가 되어야 하는 건데?!","JPN":"なんでこの私があんたたちのせいで負けなきゃならないの！？","ENG":"I lost because of you!","TWN":"憑什麼我要受你們拖累成為失敗者？！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"학생회 임원이란 녀석은 점수도 하나 못 얻고 말이야!","JPN":"生徒会役員とかいうやつは1点すら取れてないし！","ENG":"And the Student Council member here couldn't even manage a single point!","TWN":"身為學生會管理人員，居然一分都沒拿到！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"무, 무슨 소리야! 난 꼬리를 세 개나 모았는걸!","JPN":"な、なに言ってるの！　あたしはしっぽを3つも取れたよ？","ENG":"W-what are you talking about? I collected three tails!","TWN":"你，你那是什麼話！我本來拿到了三條尾巴呢！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"결국 내 꼬리를 뺏겨서 0점이 되긴 했지만......","JPN":"結局自分のしっぽを取られて0点になったけど……","ENG":"And then, I lost mine, along with all my points...","TWN":"只不過最後都被搶走了，所以才變成了零分……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"......그, 그러는 나이엘 너야말로 팀원들을 하나도 안 도와 줬잖아!","JPN":"……そ、そういうナイエルこそ、チームメンバーたちを全然助けてあげなかったじゃない！","ENG":"B-but what about you, Naielle? You didn't help the rest of us!","TWN":"……那，奈爾你呢，你也沒幫隊員啊！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"결승에 올라가려면 팀이 승리해야 해.","JPN":"決勝に進むにはチームが勝たないと意味ないよ？","ENG":"To enter the finals, we must win as a team.","TWN":"只有隊伍獲勝才能進入決賽。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그러니까 우리 둘 다 다음 경기 땐 다른 동료들과 제대로 협력하자.","JPN":"だからあたしたち二人とも次の試合の時は他の仲間とちゃんと協力しよう。","ENG":"How about we both cooperate with our teammates during the next game?","TWN":"所以，下一場比賽時，我們兩個跟其他隊友好好配合吧。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"동료? 누가 누구랑?","JPN":"仲間？　誰と誰が？","ENG":"Who are you talking about, teammates?","TWN":"隊友？你指誰啊？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"잘 모르는 모양인데 너희들 위치를 다시 알려주지.","JPN":"よくわかってないようだから、あんたたちの立ち位置をもう一度教えてやるわ。","ENG":"In case you forgot, let me remind you.","TWN":"你們還沒搞清楚自己的位置，那我就再說一遍。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"내가 대장이고! 너흰 내 부하들이야!","JPN":"私は隊長で！　あんたたちは部下なの！","ENG":"I'm the captain. You're the subordinates!","TWN":"我是隊長！你們都是我的部下！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"알겠어? 너희들은 그냥 내가 시키는 대로만 하면 된다고!","JPN":"わかる？　三流のあんたたちは私に言われた通りにすればいいの！","ENG":"Get it? You just do as I say!","TWN":"明白了嗎？你們只要按照我說的去做就行了！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐? 누가 네 부하라는 건데?! 이 왕재수 밥통 같은 게!","JPN":"は？　誰があなたの部下なの！？　もう、自己中すぎて本当にムカつく！","ENG":"What? We're not your subordinates! You arrogant, thick-headed moose!","TWN":"什麼？你說誰是你的部下？！你這個傲嬌鬼！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"역시 처음부터 말도 안 됐어! 너 같은 애랑 한 팀이라니!","JPN":"やっぱり無理だよ！　あなたみたいなわがままな子とは同じチームでやってられないわ！","ENG":"I knew from the beginning this wouldn't work. I don't want to be on the same team as you!","TWN":"果然是從一開始就錯了！我居然跟你這種傢伙一隊！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"하, 누가 할 소릴......","JPN":"ふん、それはこっちのセリフよ！","ENG":"Hah! As if I do!","TWN":"蛤，這話應該我說才是……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"나도 이딴 머저리들만 있는 팀은 포기야.","JPN":"私だってこんなチンケなチームはお手上げ。","ENG":"I don't want to be on a team full of imbeciles, either.","TWN":"我也要放棄這種只有蠢貨的隊伍。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"애초에 나 같은 엘리트가 너희 같은 삼류들이랑 어울릴 수 있을 리가 없지.","JPN":"そもそも私みたいなエリートがあんたたちみたいな三流と一緒にやるのがあり得なかったんだわ。","ENG":"There's no way an elite like me can work with third-rate people like you.","TWN":"我這種精英就不該跟你們這些三流為伍。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"어차피 난 개인 점수만 갖고도 결승에 나갈 수 있거든.","JPN":"どうせ私は個人点数だけで決勝に出られるからね。","ENG":"I can make it to the finals purely based on my individual points.","TWN":"反正只拿到個人分數，我也能晉級決賽。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"그러니까 너희들은 탈락하든지 말든지 알아서 하라고!","JPN":"だからあんたたちは脱落でも何でも勝手にすればいい！","ENG":"You go ahead and get yourselves eliminated or whatever!","TWN":"所以，你們淘汰不淘汰的，自己看著辦吧！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나, 나이엘! 너 거기 서! 야!","JPN":"ナ、ナイエル！　待って！　待ってってば！","ENG":"N-Naielle! Stop right there! Hey!","TWN":"奈，奈爾！你站住！喂！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......지나가다 들었는데 조금 미안하네.","JPN":"……通りすがりに聞いちゃったけど、ちょっと悪いわね。","ENG":"I happened to overhear you guys. I'm sorry.","TWN":"……我路過時不小心聽到了，抱歉。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"살짝만 긁어 줄 생각이었는데 이렇게 크게 터져버릴 줄은 몰랐어.","JPN":"少しイラっとさせたかっただけなのに、こんなことになるとは思わなかったわ。","ENG":"I just wanted to tease her a bit. I didn't know she'd blow up like that.","TWN":"我本來就是想稍微教訓她一下，沒想到事情會變得這麼嚴重。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"임시 편입생?","JPN":"臨時編入生？","ENG":"Temporary transfer student?","TWN":"臨時插班生？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"하아...... 네 탓 아니야. 저 성질머리를 누가 말려.","JPN":"ふう……あなたのせいじゃないよ。あの性格は誰にも止められないんだから。","ENG":"*Sigh* It's not your fault. She's just so spoiled.","TWN":"唉啊……不是你的錯，她就是那個臭脾氣。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런 주제에 실력은 좋아서 힘으로 어떻게 할 수도 없고.","JPN":"あんなのでも実力はあるから、力で何とかすることもできないし。","ENG":"But she's so strong that there's not much we can do to change her mind.","TWN":"偏偏實力又好，我也不能拿她怎麼樣。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그나저나 너희 팀은 누가 점수를 냈어?","JPN":"ところで、そっちのチームは誰の点数が高かったの？","ENG":"By the way, who scored the points in your team?","TWN":"話說回來，你們隊誰得分了？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"정신차리고 보니까 꼬리를 다 빼앗겨 버렸더라고.","JPN":"気づいたらしっぽを全部取られてしまっていたの。","ENG":"One of you took all our tails before we knew it.","TWN":"我的尾巴不知道什麼時候被搶走的，我完全沒有發現。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런 슈퍼플레이를 할 줄 아는 학생이 있으면 모를 리가 없는데......","JPN":"あんなスーパープレイができる子が学校にいるなら、知らないはずがないのに……","ENG":"Anyone that good has to be famous.","TWN":"如果有那麼厲害的學生參賽的話，我沒理由不認識啊……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그러고 보니 누구였더라?","JPN":"そういえば誰だろう？","ENG":"Now that you said that, who was it?","TWN":"我想想，那個人是誰？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"모르는 꼬마애가 자기한테 맡겨 달라고 한 것 같았는데...... 어쩐지 잘 기억이 안 나네.","JPN":"知らない子に、自分に任せてと言われたような気がするけど……なぜか思い出せない。","ENG":"I think some strange girl told us to count on her, but... for some reason, I can't remember.","TWN":"好像有個不認識的孩子說一切交給她就好……我記不清了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그 말은 혹시...... 존재하지 않는 31번?","JPN":"それはもしかして……存在しない31番？","ENG":"Can it be... Number Thirty-one, the one who doesn't exist?","TWN":"難道……是不存在的31號？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"왜? 아는 애야?","JPN":"うん？　知り合いなの？","ENG":"Huh? Do you know her?","TWN":"怎麼了？你認識她？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아니. 요즘 다시 아카데미에 도는 괴담이야.","JPN":"ううん、最近アカデミー内で流れている怪談があってね。","ENG":"No, but there's this urban legend that's been circulating in the Academy.","TWN":"不是，最近學院又開始流傳一個怪談。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그것 때문에 운동회를 참가하려는 학생들이 줄어들어서 아티팩트까지 상품으로 내걸었다고 들었거든.","JPN":"そのせいで運動会に参加する生徒が減って、\\n優勝賞品にアーティファクトまで出すようになったって聞いたの。","ENG":"It turned so many students off from this Field Day that the Academy had to put up the Artifact as a prize.","TWN":"聽說因為這個，參加運動會的學生都減少了，所以學院才會拿出人造神器作為優勝獎品。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"흐음...... 학교마다 무서운 얘기가 있다던데, 아카데미도 예외는 아닌가 보네.","JPN":"なるほど……学校ごとに怪談があるらしいという話は\\n聞いていたけど、アカデミーも例外ではなかったんだね。","ENG":"Hmm... Every school has an urban legend or two, and the Academy is no exception.","TWN":"嗯……都說每所學校都有恐怖故事，看來學院也不例外啊。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"뭐, 누군지는 다음에 다시 만나 보면 알게 되겠지.","JPN":"まあ、誰なのかは今度また会った時にわかるでしょう。","ENG":"Well, I'll find out who she is if I see her again.","TWN":"算了，下次再見時應該就知道是誰了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}}]`);export{e as default};